return (async () => {
    // Saháme přímo do výsledku předchozího Selectu
    const advisor = context.workflow['c19a733b-4769-4b4a-84a0-190618a02247'].result?.[0];

    if (!advisor) throw new Error("Data o poradci nebyla nalezena.");

    const response = await fetch(
        "https://fzkliiqpeffdxnoykdsl.supabase.co/functions/v1/google-task-lists",
        {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ advisor_id: advisor.user_id }),
        }
    );

    const result = await response.json();
    if (!response.ok) throw new Error(result.error || "Chyba na straně Supabase");

    return result.task_lists;
})();

