const userId =
  pluginVariables['1fa0dd68-5069-436c-9a7d-3b54c340f1fa']?.user?.id;

if (!userId) {
  alert('Nejste přihlášeni!');
  return;
}

const authUrl =
  `https://fzkliiqpeffdxnoykdsl.supabase.co/functions/v1/google-oauth-start?advisor_id=${userId}`;

const width = 600;
const height = 700;
const left = (screen.width - width) / 2;
const top = (screen.height - height) / 2;

window.open(
  authUrl,
  'Google Tasks',
  `width=${width},height=${height},left=${left},top=${top}`
);
